import React, { useState, useEffect } from 'react';
import { 
  Paper, 
  BottomNavigation as MuiBottomNavigation, 
  BottomNavigationAction,
  Box,
  Badge,
  useMediaQuery
} from '@mui/material';
import { styled, alpha, useTheme } from '@mui/material/styles';
import { 
  Home, 
  EmojiEvents, 
  Person, 
  DirectionsCar,
  Notifications
} from '@mui/icons-material';
import { useLocation, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';

// Объявляем расширенный интерфейс Window для типизации Telegram WebApp
declare global {
  interface Window {
    Telegram?: {
      WebApp?: {
        BackButton?: {
          isVisible: boolean;
          show: () => void;
          hide: () => void;
          onClick: (callback: () => void) => void;
        };
        MainButton?: {
          text: string;
          color: string;
          textColor: string;
          isVisible: boolean;
          isActive: boolean;
          isProgressVisible: boolean;
          show: () => void;
          hide: () => void;
          onClick: (callback: () => void) => void;
        };
        setHeaderColor: (color: string) => void;
        ready: () => void;
        expand: () => void;
        close: () => void;
      };
    };
  }
}

const StyledBottomNavigation = styled(Paper)(({ theme }) => ({
  position: 'fixed',
  bottom: 0,
  left: 0,
  right: 0,
  zIndex: 100,
  borderTopLeftRadius: theme.shape.borderRadius * 3,
  borderTopRightRadius: theme.shape.borderRadius * 3,
  overflow: 'hidden',
  boxShadow: '0 -2px 20px rgba(0,0,0,0.08)',
  backgroundColor: theme.palette.mode === 'light' 
    ? alpha(theme.palette.background.paper, 0.95)
    : alpha(theme.palette.background.paper, 0.92),
  backdropFilter: 'blur(10px)',
  borderTop: `1px solid ${theme.palette.divider}`,
  height: 65,
  paddingBottom: 'env(safe-area-inset-bottom)',
}));

const AnimatedNavAction = styled(motion.div)({
  flex: 1,
  display: 'flex',
  justifyContent: 'center',
  position: 'relative',
});

const NavIndicator = styled(motion.div)(({ theme }) => ({
  width: 4,
  height: 4,
  borderRadius: '50%',
  backgroundColor: theme.palette.primary.main,
  position: 'absolute',
  bottom: 8,
  boxShadow: `0 0 8px ${theme.palette.primary.main}`,
}));

const StyledBottomNavigationAction = styled(BottomNavigationAction)(({ theme }) => ({
  minWidth: 'auto',
  padding: '10px 0 8px',
  '&.Mui-selected': {
    paddingTop: 8,
    '& .MuiBottomNavigationAction-label': {
      fontWeight: 600,
    },
    '& .MuiSvgIcon-root': {
      color: theme.palette.primary.main,
    },
  },
  '& .MuiBottomNavigationAction-label': {
    fontSize: '0.7rem',
    fontWeight: 500,
    transition: 'all 0.2s ease',
    marginTop: 3,
  },
}));

interface BottomNavigationBarProps {
  hasNotifications?: boolean;
}

const BottomNavigationBar: React.FC<BottomNavigationBarProps> = ({ hasNotifications = true }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const currentPath = location.pathname.split('/')[1] || '/';
  const [mounted, setMounted] = useState(false);
  
  // Определяем, находимся ли мы в Telegram Mini App
  const [isTelegramMiniApp, setIsTelegramMiniApp] = useState(false);
  
  useEffect(() => {
    // Проверка на Telegram Mini App через window.Telegram
    try {
      const isTelegram = Boolean(window.Telegram?.WebApp);
      setIsTelegramMiniApp(isTelegram);
    } catch (e) {
      setIsTelegramMiniApp(false);
    }
    
    setMounted(true);
  }, []);
  
  const handleChange = (event: React.SyntheticEvent<Element, Event>, newValue: string) => {
    navigate(newValue);
  };
  
  if (!mounted) return null;
  
  return (
    <StyledBottomNavigation
      elevation={0}
      className="safe-area-padding-bottom"
      sx={{ 
        height: isTelegramMiniApp ? 75 : 65,
        display: { xs: 'block', md: isTelegramMiniApp ? 'block' : 'none' }
      }}
    >
      <MuiBottomNavigation
        value={currentPath === '/' ? '/' : `/${currentPath}`}
        onChange={handleChange}
        showLabels
        sx={{
          height: '100%',
          justifyContent: 'space-around',
          px: 1,
        }}
      >
        <AnimatedNavAction>
          <StyledBottomNavigationAction 
            label="Главная" 
            value="/" 
            icon={<Home />} 
          />
          {currentPath === '/' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
        
        <AnimatedNavAction>
          <StyledBottomNavigationAction 
            label="Розыгрыши" 
            value="/raffles" 
            icon={<DirectionsCar />} 
          />
          {currentPath === 'raffles' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
        
        <AnimatedNavAction>
          <StyledBottomNavigationAction 
            label="Награды" 
            value="/rewards" 
            icon={<EmojiEvents />} 
          />
          {currentPath === 'rewards' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
        
        <AnimatedNavAction>
          <StyledBottomNavigationAction 
            label="Уведомления" 
            value="/notifications" 
            icon={
              <Badge 
                color="error" 
                variant="dot" 
                invisible={!hasNotifications}
                sx={{ 
                  '& .MuiBadge-badge': {
                    top: 3,
                    right: 3,
                    boxShadow: `0 0 0 2px ${theme.palette.background.paper}`
                  }
                }}
              >
                <Notifications />
              </Badge>
            } 
          />
          {currentPath === 'notifications' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
        
        <AnimatedNavAction>
          <StyledBottomNavigationAction 
            label="Профиль" 
            value="/profile" 
            icon={<Person />} 
          />
          {currentPath === 'profile' && <NavIndicator layoutId="navIndicator" />}
        </AnimatedNavAction>
      </MuiBottomNavigation>
    </StyledBottomNavigation>
  );
};

export default BottomNavigationBar;
